var e=JSON.parse(`[{"id":"L2_1","type":"narration","speaker":null,"text":{"KOREA":"내가 봐야 할 사람은, 하나뿐이었다.","JPN":"私が見るべき人は、一人しかいなかった。","ENG":"I had only one person to look up to in my life.","TWN":"我該注視的人，就只有一位。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"COUNT_NPC_NULL_NULL","text":{"KOREA":"샬롯, 넌 무엇이냐?","JPN":"シャーロット、お前は何者だ？","ENG":"Carlota, what are you?","TWN":"夏洛特，你是誰？"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"COUNT_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"가문의…… 일부입니다.","JPN":"一族の……一部です。","ENG":"I am a part of the family.","TWN":"我是家族的……一部分。"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"COUNT_NPC_NULL_NULL","text":{"KOREA":"그렇다면 가문은 무엇이냐?","JPN":"ならば一族とは何だ？","ENG":"What is the family?","TWN":"那家族是什麼？"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"COUNT_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"저의 모든 것입니다.","JPN":"私のすべてです。","ENG":"My everything.","TWN":"是我的一切。"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"COUNT_NPC_NULL_NULL","text":{"KOREA":"그렇다. 귀족이란 오직 가문을 위해 살고, 가문을 위해 죽어야 한다.","JPN":"そうだ。貴族とは一族のために生き、一族のために死ななければならない。","ENG":"Yes. A noble should live for the family, and die for the family.","TWN":"很好，所謂的貴族，就是生是為家族而生，死也是為家族而死。"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"COUNT_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"COUNT_NPC_NULL_NULL","text":{"KOREA":"가문이 없으면 너는 아무것도 아니다.","JPN":"一族が無ければ、お前は何者でもない。","ENG":"You’re nothing without the family.","TWN":"沒有家族的話你什麼也不是。"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"COUNT_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"COUNT_NPC_NULL_NULL","text":{"KOREA":"살아있는 동안은 물론 죽어서라도, 의식의 한 조각이나마 남아 있다면……","JPN":"生きている間はもちろん、死んだとしても、意識が一欠片だけでも残っているのなら……","ENG":"While you live, or even after you’re dead if you can...","TWN":"在你活著的時候，甚至是死後，就算你僅存最後一絲意識……"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"COUNT_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"COUNT_NPC_NULL_NULL","text":{"KOREA":"오직 가문을 위해 네 모든 것을 바쳐야 한다.","JPN":"一族のために、お前のすべてを捧げなければならない。","ENG":"Sacrifice everything you have for the family.","TWN":"也要為家族獻出你的全所有。"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"COUNT_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"COUNT_NPC_NULL_NULL","text":{"KOREA":"이 아비 앞에서 맹세해라.","JPN":"この父の前で誓え。","ENG":"Swear it in front of me.","TWN":"我要你在爸爸的面前發誓。"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"COUNT_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"……맹세하겠습니다, 아버지.","JPN":"……誓います、お父様。","ENG":"I swear it, father.","TWN":"……我發誓。"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"EXECUTE_NPC_NULL_NULL","text":{"KOREA":"시간이 되었다, 백작! 아니, 반역자!","JPN":"時間だ、伯爵！　いや、反逆者！","ENG":"It’s your time, Count! No, traitor!","TWN":"伯爵…不對，逆賊！時候到了！"},"stage":{"bg":"CASTLE_02","slots":{"L":{"char_id":"COUNT_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EXECUTE_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"COUNT_NPC_NULL_NULL","text":{"KOREA":"샬롯! 네가 가문을 되살려야 한다! 알겠느냐!","JPN":"シャーロット！　お前がマルチネス家を再建するのだ！　わかったか！","ENG":"Carlota! You have to restore our family! Do not forget!","TWN":"夏洛特！你一定要復興家族！知道嗎！"},"stage":{"bg":"CASTLE_02","slots":{"L":{"char_id":"COUNT_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EXECUTE_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"EXECUTE_NPC_NULL_NULL","text":{"KOREA":"시끄러워! 당장 끌어내라!","JPN":"うるさい！　今すぐ引きずり出せ！","ENG":"Shut up! Get him out now!","TWN":"吵死了！立刻帶走！"},"stage":{"bg":"CASTLE_02","slots":{"L":{"char_id":"COUNT_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EXECUTE_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"COUNT_NPC_NULL_NULL","text":{"KOREA":"샬롯! 절대 잊지 마라! 넌 오로지 가문을 위해……!!","JPN":"シャーロット！　決して忘れるな！　お前は何があろうと一族のために……！！","ENG":"Carlota! Do not forget! Your family is everything you have!","TWN":"夏洛特！千萬要記住！你是為家族而……！！"},"stage":{"bg":"CASTLE_02","slots":{"L":{"char_id":"COUNT_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EXECUTE_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"……","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CASTLE_02","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"이걸로 끝인가, 알렌 경?","JPN":"これで最後か、バーミンガム卿？","ENG":"Are we done now, Sir Allen?","TWN":"就這樣結束了嗎，艾倫愛卿？"},"stage":{"bg":"CASTLE_02","slots":{"L":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};